import sys
from sys import stdin

def solve():
    input_data = stdin.read().split()
    idx = 0
    t = int(input_data[idx]); idx+=1
    for _ in range(t):
        n, k = int(input_data[idx]), int(input_data[idx+1]); idx+=2
        mines = []
        for i in range(n):
            x, y, timer = int(input_data[idx]), int(input_data[idx+1]), int(input_data[idx+2])
            idx+=3
            mines.append((x, y, timer))

        parent = list(range(n))
        def find(a):
            while parent[a] != a:
                parent[a] = parent[parent[a]]
                a = parent[a]
            return a
        def union(a, b):
            a, b = find(a), find(b)
            if a != b: parent[a] = b

        # Group by x
        from collections import defaultdict
        by_x = defaultdict(list)
        by_y = defaultdict(list)
        for i, (x, y, timer) in enumerate(mines):
            by_x[x].append((y, i))
            by_y[y].append((x, i))

        for x, lst in by_x.items():
            lst.sort()
            for j in range(1, len(lst)):
                if lst[j][0] - lst[j-1][0] <= k:
                    union(lst[j][1], lst[j-1][1])

        for y, lst in by_y.items():
            lst.sort()
            for j in range(1, len(lst)):
                if lst[j][0] - lst[j-1][0] <= k:
                    union(lst[j][1], lst[j-1][1])

        comp_min = {}
        for i, (x, y, timer) in enumerate(mines):
            r = find(i)
            if r not in comp_min or timer < comp_min[r]:
                comp_min[r] = timer

        min_timers = sorted(comp_min.values())

        lo, hi = 0, 10**9
        while lo < hi:
            mid = (lo + hi) // 2
            import bisect
            need = len(min_timers) - bisect.bisect_right(min_timers, mid)
            if need <= mid + 1:
                hi = mid
            else:
                lo = mid + 1
        print(lo)

solve()
